SELECT DISTINCT r.code
FROM role r
JOIN (
    SELECT role_id FROM user_global_role WHERE user_id = #{userId}
    UNION
    SELECT role_id FROM user_domain_role WHERE user_id = #{userId}
) rs ON rs.role_id = r.id
ORDER BY r.code

